import{_ as t,S as l,n as a,p as d,q as r,J as i,C as n,A as s,a3 as u}from"./framework-3c337068.js";const c={},m={class:"table-of-contents"};function p(h,e){const o=l("router-link");return a(),d("div",null,[e[18]||(e[18]=r("h1",{id:"repositories-mirrors",tabindex:"-1"},[r("a",{class:"header-anchor",href:"#repositories-mirrors","aria-hidden":"true"},"#"),i(" Repositories & Mirrors")],-1)),e[19]||(e[19]=r("h2",{id:"mirror-migration-for-new-cloudlinux-versions",tabindex:"-1"},[r("a",{class:"header-anchor",href:"#mirror-migration-for-new-cloudlinux-versions","aria-hidden":"true"},"#"),i(" Mirror Migration for New CloudLinux Versions")],-1)),e[20]||(e[20]=r("p",null,"This section explains why the old mirror system will not support newer CloudLinux OS/package versions, and how to migrate to the new mirror configuration.",-1)),r("nav",m,[r("ul",null,[r("li",null,[n(o,{to:"#mirror-migration-for-new-cloudlinux-versions"},{default:s(()=>e[0]||(e[0]=[i("Mirror Migration for New CloudLinux Versions",-1)])),_:1,__:[0]})]),r("li",null,[n(o,{to:"#summary"},{default:s(()=>e[1]||(e[1]=[i("Summary",-1)])),_:1,__:[1]})]),r("li",null,[n(o,{to:"#what-is-changing"},{default:s(()=>e[2]||(e[2]=[i("What is changing",-1)])),_:1,__:[2]})]),r("li",null,[n(o,{to:"#why-the-old-system-will-not-work-for-newer-versions"},{default:s(()=>e[3]||(e[3]=[i("Why the old system will not work for newer versions",-1)])),_:1,__:[3]})]),r("li",null,[n(o,{to:"#what-you-need-to-do-migration-quick-plan"},{default:s(()=>e[4]||(e[4]=[i("What you need to do (migration quick plan)",-1)])),_:1,__:[4]})]),r("li",null,[n(o,{to:"#creating-a-cloudlinux-mirror-swng"},{default:s(()=>e[5]||(e[5]=[i("Creating a CloudLinux Mirror (SWNG)",-1)])),_:1,__:[5]}),r("ul",null,[r("li",null,[n(o,{to:"#minimum-requirements-for-a-supported-mirror"},{default:s(()=>e[6]||(e[6]=[i("Minimum requirements for a supported mirror",-1)])),_:1,__:[6]})]),r("li",null,[n(o,{to:"#step-by-step-mirror-swng"},{default:s(()=>e[7]||(e[7]=[i("Step-by-step: mirror SWNG",-1)])),_:1,__:[7]})]),r("li",null,[n(o,{to:"#optional-mirror-repo-cloudlinux-com-content"},{default:s(()=>e[8]||(e[8]=[i("Optional: mirror repo.cloudlinux.com content",-1)])),_:1,__:[8]})]),r("li",null,[n(o,{to:"#information-to-provide-to-cloudlinux-support"},{default:s(()=>e[9]||(e[9]=[i("Information to provide to CloudLinux Support",-1)])),_:1,__:[9]})])])]),r("li",null,[n(o,{to:"#self-diagnostics-mirror-server"},{default:s(()=>e[10]||(e[10]=[i("Self-diagnostics (mirror server)",-1)])),_:1,__:[10]}),r("ul",null,[r("li",null,[n(o,{to:"#connectivity-to-upstream"},{default:s(()=>e[11]||(e[11]=[i("Connectivity to upstream",-1)])),_:1,__:[11]})]),r("li",null,[n(o,{to:"#rsync-checks"},{default:s(()=>e[12]||(e[12]=[i("RSync checks",-1)])),_:1,__:[12]})]),r("li",null,[n(o,{to:"#https-checks-your-mirror"},{default:s(()=>e[13]||(e[13]=[i("HTTPS checks (your mirror)",-1)])),_:1,__:[13]})]),r("li",null,[n(o,{to:"#storage-permissions-and-sync-hygiene"},{default:s(()=>e[14]||(e[14]=[i("Storage, permissions, and sync hygiene",-1)])),_:1,__:[14]})])])]),r("li",null,[n(o,{to:"#troubleshooting"},{default:s(()=>e[15]||(e[15]=[i("Troubleshooting",-1)])),_:1,__:[15]}),r("ul",null,[r("li",null,[n(o,{to:"#connection-issues"},{default:s(()=>e[16]||(e[16]=[i("Connection issues",-1)])),_:1,__:[16]})]),r("li",null,[n(o,{to:"#sync-failures"},{default:s(()=>e[17]||(e[17]=[i("Sync failures",-1)])),_:1,__:[17]})])])])])]),e[21]||(e[21]=u(`<h2 id="summary" tabindex="-1"><a class="header-anchor" href="#summary" aria-hidden="true">#</a> Summary</h2><p>New CloudLinux versions are moving to the new mirror service and open HTTPS mirrors. The legacy mirror system (custom SSL/XMLRPC) will not support newer OS and package versions. Customers should reconfigure their mirrors to the new standard HTTPS layout and endpoint.</p><p><strong>Currently, only CloudLinux OS 10 is supported</strong>, and support for older versions will be enabled gradually.</p><p>For customer-managed mirrors, the migration means <strong>adding a new HTTPS mirror</strong> (or <strong>replacing</strong> the legacy mirror endpoint) rather than &quot;reconfiguring&quot;. In most cases you can <strong>reuse existing storage</strong> and just adjust the mirror layout/paths and transport (open HTTPS).</p><h2 id="what-is-changing" tabindex="-1"><a class="header-anchor" href="#what-is-changing" aria-hidden="true">#</a> What is changing</h2><ul><li>Legacy mirrors used custom SSL and XMLRPC transport.</li><li>New mirrors use standard HTTPS and normal directory browsing.</li><li>The mirrorlist endpoint is now <code>cl-mirrors</code> (not <code>cln-mirrors</code>).</li><li>The new system supports partial mirrors (only the OS versions you need).</li></ul><h2 id="why-the-old-system-will-not-work-for-newer-versions" tabindex="-1"><a class="header-anchor" href="#why-the-old-system-will-not-work-for-newer-versions" aria-hidden="true">#</a> Why the old system will not work for newer versions</h2><ul><li>Newer CloudLinux tooling uses the <strong>new mirrorlist endpoint</strong> (<code>cl-mirrors</code>) and standard HTTPS mirrors.</li><li>The legacy XMLRPC/custom SSL flow is being phased out.</li><li>Mirrors that only support the old endpoint (<code>cln-mirrors</code>) may not be selected by updated systems.</li></ul><h2 id="what-you-need-to-do-migration-quick-plan" tabindex="-1"><a class="header-anchor" href="#what-you-need-to-do-migration-quick-plan" aria-hidden="true">#</a> What you need to do (migration quick plan)</h2><ol><li><strong>Set up a new HTTPS mirror</strong> that exposes SWNG content via standard HTTPS.</li><li><strong>Use the new mirrorlist endpoint</strong>: <ul><li><code>https://repo.cloudlinux.com/cloudlinux/mirrorlists/cl-mirrors</code></li></ul></li><li><strong>Optionally mirror only the versions you need</strong> (partial mirrors are supported).</li><li><strong>Provide your mirror URL and scope</strong> to CloudLinux support so it can be added to mirror rotation.</li></ol><div class="tip custom-block"><p class="custom-block-title"></p><ul><li>SWNG is the main operational repository for updates.</li><li><code>repo.cloudlinux.com</code> contains conversion and install assets.</li><li>Full <code>repo.cloudlinux.com</code> is large (&gt;3 TB), so partial sync is recommended unless you need a fully autonomous environment.</li></ul></div><h2 id="creating-a-cloudlinux-mirror-swng" tabindex="-1"><a class="header-anchor" href="#creating-a-cloudlinux-mirror-swng" aria-hidden="true">#</a> Creating a CloudLinux Mirror (SWNG)</h2><h3 id="minimum-requirements-for-a-supported-mirror" tabindex="-1"><a class="header-anchor" href="#minimum-requirements-for-a-supported-mirror" aria-hidden="true">#</a> Minimum requirements for a supported mirror</h3><p>Your mirror should meet these requirements to be eligible for inclusion in the mirror service:</p><ul><li><strong>HTTPS access</strong> with a valid certificate from a public CA (e.g., Let&#39;s Encrypt)</li><li><strong>Correct base paths</strong> (recommended layout): <ul><li><code>https://mirror.example.com/swng/</code> for SWNG</li><li>(optional) <code>https://mirror.example.com/cloudlinux/</code> for <code>repo.cloudlinux.com</code> content</li></ul></li><li><strong>No authentication</strong> for repository downloads</li><li><strong>Repository metadata is accessible</strong> (e.g., <code>repodata/repomd.xml</code> for the mirrored trees)</li><li><strong>Regular sync schedule</strong> (cron/systemd timer) and enough disk space for the chosen scope</li></ul><h3 id="step-by-step-mirror-swng" tabindex="-1"><a class="header-anchor" href="#step-by-step-mirror-swng" aria-hidden="true">#</a> Step-by-step: mirror SWNG</h3><p><strong>1. Prepare storage</strong></p><p>Use a dedicated disk or partition. Plan for approximately 500 GB for SWNG.</p><p><strong>2. Sync SWNG</strong></p><p>Use rsync from the upstream endpoint:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># Example: mirror all SWNG
rsync -avH --delete --numeric-ids --safe-links \\
  rsync://rsync.upstream.cloudlinux.com/SWNG/ \\
  /var/www/mirrors/swng/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>If you only need specific versions, mirror only those subpaths (partial mirrors):</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># Example: mirror CloudLinux 10 SWNG only
mkdir -p /var/www/mirrors/swng/10
rsync -avH --delete --numeric-ids --safe-links \\
  rsync://rsync.upstream.cloudlinux.com/SWNG/10/ \\
  /var/www/mirrors/swng/10/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>3. Expose via HTTPS</strong></p><p>Configure Nginx (or another web server). Enable directory browsing and ensure HTTPS works with a valid certificate.</p><p><strong>4. Validate the public index</strong></p><p>Ensure the index matches the upstream structure. Mixed setups can use <code>&lt;domain&gt;/swng/</code>.</p><h3 id="optional-mirror-repo-cloudlinux-com-content" tabindex="-1"><a class="header-anchor" href="#optional-mirror-repo-cloudlinux-com-content" aria-hidden="true">#</a> Optional: mirror <code>repo.cloudlinux.com</code> content</h3><p>Use this only if you need a fully autonomous install/conversion environment:</p><ul><li>Full sync is <strong>3+ TB</strong>.</li><li>In most cases, sync only the required sub-repositories.</li></ul><p>If you decide to mirror it, use the upstream rsync module:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>rsync -avH --delete --numeric-ids --safe-links \\
  rsync://rsync.upstream.cloudlinux.com/CLOUDLINUX/ \\
  /var/www/mirrors/cloudlinux/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="information-to-provide-to-cloudlinux-support" tabindex="-1"><a class="header-anchor" href="#information-to-provide-to-cloudlinux-support" aria-hidden="true">#</a> Information to provide to CloudLinux Support</h3><p>When contacting CloudLinux Support to register your mirror, provide:</p><ul><li>Mirror URL (HTTPS), e.g. <code>https://mirror.example.com/swng/</code></li><li>Whether the mirror is <strong>public</strong> or <strong>private</strong></li><li>For private mirrors: list of IPs or networks</li><li>Geographic location (country/city)</li><li>Available bandwidth/capacity</li><li>Sync method and frequency</li><li>Whether the mirror is <strong>complete</strong> or <strong>partial</strong></li><li>If partial: list the versions mirrored</li></ul><h2 id="self-diagnostics-mirror-server" tabindex="-1"><a class="header-anchor" href="#self-diagnostics-mirror-server" aria-hidden="true">#</a> Self-diagnostics (mirror server)</h2><p>This section helps you verify your mirror is healthy before contacting Support.</p><h3 id="connectivity-to-upstream" tabindex="-1"><a class="header-anchor" href="#connectivity-to-upstream" aria-hidden="true">#</a> Connectivity to upstream</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># DNS resolution
nslookup upstream.cloudlinux.com

# HTTPS connectivity (for browsing)
curl -fsSI https://upstream.cloudlinux.com/ | head

# RSync endpoint listing (should return module list)
rsync rsync://rsync.upstream.cloudlinux.com/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>If you are behind a corporate proxy/firewall, ensure outbound access from the mirror host:</p><ul><li>TCP <strong>873</strong> to <code>rsync.upstream.cloudlinux.com</code> (rsync)</li><li>TCP <strong>443</strong> to <code>upstream.cloudlinux.com</code> (HTTPS browsing/validation)</li></ul><h3 id="rsync-checks" tabindex="-1"><a class="header-anchor" href="#rsync-checks" aria-hidden="true">#</a> RSync checks</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># Dry-run a small test sync (replace path as needed)
mkdir -p /tmp/cl-mirror-test
rsync -avv --delete rsync://rsync.upstream.cloudlinux.com/SWNG/10/ /tmp/cl-mirror-test/ | head -n 50
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Common rsync pitfalls:</p><ul><li><code>@ERROR: ...</code> typically indicates connectivity/firewall/proxy issues.</li><li>Slow sync is often disk I/O bottlenecks or too frequent <code>--delete</code> on huge trees; use a reasonable sync interval.</li></ul><h3 id="https-checks-your-mirror" tabindex="-1"><a class="header-anchor" href="#https-checks-your-mirror" aria-hidden="true">#</a> HTTPS checks (your mirror)</h3><p>Replace <code>mirror.example.com</code> with your mirror domain.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># Mirror root must be reachable via HTTPS
curl -fsSI &quot;https://mirror.example.com/swng/&quot; | head

# Metadata must exist for mirrored subtrees (example for CL10 x86_64)
curl -fsSI &quot;https://mirror.example.com/swng/10/x86_64/repodata/repomd.xml&quot; | head
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>If you use a different layout (e.g., you expose SWNG at <code>/</code>), adjust paths accordingly. Trailing slashes matter for some web server configurations.</p><h3 id="storage-permissions-and-sync-hygiene" tabindex="-1"><a class="header-anchor" href="#storage-permissions-and-sync-hygiene" aria-hidden="true">#</a> Storage, permissions, and sync hygiene</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># Disk space
df -h

# Basic directory permissions (adjust path to your mirror root)
ls -ld /var/www/mirrors /var/www/mirrors/swng

# Check that new files are appearing after a sync run (example)
ls -lh /var/www/mirrors/swng/10/ | head
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Recommendations:</p><ul><li>Run sync as a dedicated user that can write to the destination directory.</li><li>Ensure your HTTPS server can read the mirrored files.</li><li>Keep sync logs (cron output or systemd journal) so you can share errors with Support.</li></ul><h2 id="troubleshooting" tabindex="-1"><a class="header-anchor" href="#troubleshooting" aria-hidden="true">#</a> Troubleshooting</h2><table><thead><tr><th>Issue</th><th>Fix</th></tr></thead><tbody><tr><td><strong>Firewall blocks RSync/HTTPS</strong></td><td>Outbound from mirror host: TCP <code>873</code> (rsync) and <code>443</code> (HTTPS). Inbound to your mirror (for clients): TCP <code>443</code> (HTTPS).</td></tr><tr><td><strong>DNS fails to resolve</strong></td><td>Verify <code>/etc/resolv.conf</code>, corporate DNS rules. Run <code>nslookup upstream.cloudlinux.com</code>.</td></tr><tr><td><strong>RSync not installed</strong></td><td>Install <code>rsync</code> with your package manager, then retry the sync.</td></tr><tr><td><strong>Mirror returns 403/404</strong></td><td>Confirm the exact base paths and trailing slashes. Confirm your web server maps URLs to the correct filesystem directories. Reference: <code>https://upstream.cloudlinux.com/swng/</code> and <code>https://upstream.cloudlinux.com/cloudlinux/</code></td></tr><tr><td><strong>Insufficient disk space</strong></td><td>Run <code>df -h</code> and sync only the required sub-repositories.</td></tr><tr><td><strong>Permission errors</strong></td><td>Ensure the sync user can write to the destination directory.</td></tr><tr><td><strong>Certificate problems</strong></td><td>Renew or replace the certificate (Let&#39;s Encrypt auto-renewal recommended).</td></tr><tr><td><strong>Partial mirror not in mirrorlist</strong></td><td>Confirm the mirrored versions match the scope provided to Support. For private mirrors, confirm egress IPs match the scope. Changes may take time to propagate.</td></tr></tbody></table><h3 id="connection-issues" tabindex="-1"><a class="header-anchor" href="#connection-issues" aria-hidden="true">#</a> Connection issues</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># Test RSync connectivity
rsync rsync://rsync.upstream.cloudlinux.com/

# Test HTTP connectivity
curl -I https://upstream.cloudlinux.com/

# Check DNS resolution
nslookup upstream.cloudlinux.com
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="sync-failures" tabindex="-1"><a class="header-anchor" href="#sync-failures" aria-hidden="true">#</a> Sync failures</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># Test with verbose output
rsync -avv --delete rsync://rsync.upstream.cloudlinux.com/CLOUDLINUX/ /tmp/test-sync/

# Check disk space
df -h
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,59))])}const v=t(c,[["render",p],["__file","index.html.vue"]]);export{v as default};
